#include<bits/stdc++.h>
using namespace std;
long long ans,DP[10005];char s[10005];
int main(void){
	scanf("%s",s+1);
	for(int i=1;i<=strlen(s+1);i++)
		if((!(s[i]=='('||s[i]=='['||s[i]=='{'))&&s[i]==')'&&s[i-1-DP[i-1]]=='('||s[i]==']'&&s[i-1-DP[i-1]]=='['||s[i]=='}'&&s[i-1-DP[i-1]]=='{')DP[i]=DP[i-1]+2+DP[i-2-DP[i-1]],ans=max(ans,DP[i]);		
	cout<<ans;
	return false;
}
